# 3. DEFINE THE ATTACK PARAMETERS [cite: 79, 84]
# Alice has 66,850. Original message was 3. 
# 66850 // 3 = 22283. New amount = 66,849.
k = 22283 

# 4. COMPUTE MANIPULATED VALUES [cite: 85]
# c2' = (c2 * k^e_Bob) % n_Bob
